from anthropic import Anthropic

client = Anthropic()

# Create a session with memory enabled
session = client.beta.sessions.create(
    environment_id=environment.id,
    agent={"type": "agent", "id": agent.id, "version": agent.version},
    betas=["memory-2025-08-25"],
)

# Upload the document to Memory first
doc_path = "data/fable.txt"
with open(doc_path) as f:
    memory.create(
        environment_id=environment.id,
        file=f,
        filename=doc_path,
        betas=["memory-2025-08-25"],
    )

# Initial multi-turn request with Memory enabled
response = client.beta.sessions.events.send(
    session.id,
    betas=["memory-2025-08-25"],
    events=[
        {
            "type": "user.message",
            "content": [{"type": "text", "text": "Read /memories/documents/fable.txt"}],
        }
    ],
)

# Print the initial response
print("\nInitial Response:")
for event in response.events:
    if hasattr(event, "content"):
        for block in event.content:
            if hasattr(block, "text"):
                print(block.text)

# Continue the conversation with another question
response = client.beta.sessions.events.send(
    session.id,
    betas=["memory-2025-08-25"],
    events=[
        {
            "type": "user.message",
            "content": [
                {"type": "text", "text": "What is the moral of the fable? (Answer in two sentences maximum)"}
            ],
        }
    ],
)

# Print the second response
print("\nSecond Response:")
for event in response.events:
    if hasattr(event, "content"):
        for block in event.content:
            if hasattr(block, "text"):
